@namespace Lumeo

@{
    var context = new MegaMenuContext(_activeItemId, EventCallback.Factory.Create<string?>(this, SetActiveItemId));
}

<nav class="@CssClass" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        <ul class="@ListCssClass" role="menubar">
            @ChildContent
        </ul>
    </CascadingValue>
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public MegaMenuOrientation Orientation { get; set; } = MegaMenuOrientation.Horizontal;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? _activeItemId;

    private string CssClass => $"relative {Class}".Trim();

    private string ListCssClass => Orientation == MegaMenuOrientation.Vertical
        ? "flex flex-col gap-1"
        : "flex items-center gap-1";

    private Task SetActiveItemId(string? value)
    {
        _activeItemId = value;
        StateHasChanged();
        return Task.CompletedTask;
    }

    public enum MegaMenuOrientation { Horizontal, Vertical }

    public record MegaMenuContext(string? ActiveItemId, EventCallback<string?> SetActiveItemId);
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Title is not null)
    {
        <h4 class="text-sm font-semibold text-foreground mb-3">@Title</h4>
    }
    <ul class="space-y-1" role="group">
        @ChildContent
    </ul>
</div>

@code {
    [Parameter] public string? Title { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"{Class}".Trim();
}

@namespace Lumeo
@using Lumeo.Services
@implements IDisposable

@{
    var itemContext = new MegaMenuItemContext(_itemId, _triggerId);
}

<CascadingValue Value="itemContext" IsFixed="false">
    @if (ChildContent is null && Href is not null)
    {
        <li role="none" class="@CssClass" @attributes="AdditionalAttributes">
            <a href="@Href"
               role="menuitem"
               class="@TriggerCssClass">
                @if (Icon is not null)
                {
                    <Blazicon Svg="@Icon" class="h-4 w-4" />
                }
                @Label
            </a>
        </li>
    }
    else
    {
        <li role="none"
            class="@CssClass"
            @onpointerenter="HandlePointerEnter"
            @onpointerleave="HandlePointerLeave"
            @attributes="AdditionalAttributes">
            <button id="@_triggerId"
                    type="button"
                    role="menuitem"
                    aria-haspopup="true"
                    aria-expanded="@(_isOpen ? "true" : "false")"
                    disabled="@Disabled"
                    class="@TriggerCssClass"
                    @onclick="HandleClick"
                    @onkeydown="HandleKeyDown">
                @if (Icon is not null)
                {
                    <Blazicon Svg="@Icon" class="h-4 w-4" />
                }
                @Label
                <Blazicon Svg="Lucide.ChevronDown" class="@ChevronCssClass" />
            </button>
            @if (_isOpen)
            {
                @ChildContent
            }
        </li>
    }
</CascadingValue>

@code {
    [CascadingParameter] public MegaMenu.MegaMenuContext Context { get; set; } = default!;
    [Parameter] public string Label { get; set; } = string.Empty;
    [Parameter] public SvgIcon? Icon { get; set; }
    [Parameter] public string? Href { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = $"megamenu-item-{Guid.NewGuid():N}";
    private readonly string _triggerId = $"megamenu-trigger-{Guid.NewGuid():N}";
    private readonly DelayedDispatch _dispatch = new();
    private const int CloseDelay = 150;

    private bool _isOpen => Context?.ActiveItemId == _itemId;

    private string CssClass => Class ?? "";

    private string TriggerCssClass => string.Join(" ", new[] { "inline-flex items-center gap-1.5 px-3 py-2 text-sm font-medium text-foreground hover:bg-accent hover:text-accent-foreground rounded-md transition-colors focus:outline-none focus:bg-accent focus:text-accent-foreground disabled:pointer-events-none disabled:opacity-50", _isOpen ? "bg-accent/50" : null }.Where(s => !string.IsNullOrWhiteSpace(s)));

    private string ChevronCssClass => string.Join(" ", new[] { "h-3 w-3 transition-transform duration-200", _isOpen ? "rotate-180" : null }.Where(s => !string.IsNullOrWhiteSpace(s)));

    // rc.44 — Approach B: pointer events gated to mouse only. Touch devices
    // open via @onclick on the inner trigger button, avoiding the
    // tap-emulated-mouseenter / lift-emulated-mouseleave race that would
    // close the submenu before the user could pick a sub-item.
    private void HandlePointerEnter(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        _dispatch.Cancel();

        if (!_isOpen)
        {
            SafeAsyncDispatcher.FireAndForget(InvokeAsync, async () =>
            {
                await Context.SetActiveItemId.InvokeAsync(_itemId);
                StateHasChanged();
            }, "MegaMenuItem.HandlePointerEnter");
        }
    }

    private void HandlePointerLeave(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        if (_isOpen)
        {
            _dispatch.Schedule(CloseDelay, () =>
            {
                SafeAsyncDispatcher.FireAndForget(InvokeAsync, async () =>
                {
                    if (Context.ActiveItemId == _itemId)
                    {
                        await Context.SetActiveItemId.InvokeAsync(null);
                        StateHasChanged();
                    }
                }, "MegaMenuItem.HandlePointerLeave");
            });
        }
    }

    private async Task HandleClick()
    {
        if (_isOpen)
        {
            await Context.SetActiveItemId.InvokeAsync(null);
        }
        else
        {
            await Context.SetActiveItemId.InvokeAsync(_itemId);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Enter":
            case " ":
                await HandleClick();
                break;
            case "Escape":
                await Context.SetActiveItemId.InvokeAsync(null);
                break;
        }
    }

    public void Dispose() => _dispatch.Dispose();

    public record MegaMenuItemContext(string ItemId, string TriggerId);
}

@namespace Lumeo

<li @attributes="AdditionalAttributes">
    <a href="@Href" class="@CssClass" aria-disabled="@(Disabled ? "true" : null)">
        @if (Icon is not null)
        {
            <Blazicon Svg="@Icon" class="h-5 w-5 mt-0.5 text-muted-foreground shrink-0" />
        }
        <div>
            <div class="text-sm font-medium text-foreground">@Title</div>
            @if (Description is not null)
            {
                <p class="text-xs text-muted-foreground mt-0.5">@Description</p>
            }
        </div>
    </a>
</li>

@code {
    [Parameter] public string Href { get; set; } = "#";
    [Parameter] public string Title { get; set; } = string.Empty;
    [Parameter] public string? Description { get; set; }
    [Parameter] public SvgIcon? Icon { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => string.Join(" ", new[] { "flex items-start gap-3 rounded-md p-2 hover:bg-accent transition-colors", Disabled ? "pointer-events-none opacity-50" : null, Class }.Where(s => !string.IsNullOrWhiteSpace(s)));
}

@namespace Lumeo

<div class="@CssClass" role="menu" @attributes="AdditionalAttributes">
    <div class="@GridCssClass">
        @ChildContent
    </div>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool FullWidth { get; set; } = true;
    [Parameter] public int Columns { get; set; } = 4;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string WidthCssClass => FullWidth ? "left-0 right-0" : "w-auto min-w-[600px]";

    private string CssClass => $"absolute top-full z-50 {WidthCssClass} bg-popover border border-border/40 rounded-lg shadow-lg p-6 {Class}".Trim();

    private string GridCssClass => Columns switch {
        1 => "grid grid-cols-1 gap-6",
        2 => "grid grid-cols-2 gap-6",
        3 => "grid grid-cols-3 gap-6",
        4 => "grid grid-cols-4 gap-6",
        5 => "grid grid-cols-5 gap-6",
        _ => "grid grid-cols-1 gap-6"
    };
}
